链表是一种常见的数据结构，用于存储一系列有序的数据项。链表有很多种类型，其中最常见的是单向链表和双向链表。下面是一个简单的单向链表的示例：

```
//定义链表节点结构体
typedef struct ListNode {
    int data;             // 节点数据
    struct ListNode *next;  // 下一个节点
} ListNode;

// 初始链表为空，头结点指针为空
ListNode * head = NULL; 

// 添加节点到链表末尾
void addNode(int dat)
{
    // 为新节点分配内存
    ListNode *newNode = malloc(sizeof(ListNode));
    newNode->data = dat;
    newNode->next = NULL;

    // 如果链表为空，则新节点直接作为头节点
    if (head == NULL) {
        head = newNode;
        return;
    }

    // 找到链表的最后一个节点，将新节点添加到其后面
    ListNode *currNode = head;
    while (currNode->next != NULL) {
        currNode = currNode->next;
    }
    currNode->next = newNode;
}

// 输出链表元素
void printList()
{
    ListNode *currNode = head;
    while (currNode != NULL) {
        printf("%d ", currNode->data);
        currNode = currNode->next;
    }
    printf("\n");
}

// 删除链表节点
void deleteNode(int dat) 
{
    // 空链表
    if (head == NULL) {
        return;
    }

    // 开始节点就是要删除的节点
    if (head->data == dat) {
        ListNode *tmp = head;
        head = head->next;
        free(tmp);
        return;
    }

    // 找到要删除节点的前一个节点 currNode
    ListNode *currNode = head;
    while (currNode->next != NULL && currNode->next->data != dat) {
        currNode = currNode->next;
    }

    // 如果找到了要删除的节点，删除它
    if (currNode->next != NULL) {
        ListNode *tmp = currNode->next;
        currNode->next = tmp->next;
        free(tmp);
    }
}

// 主函数
int main() 
{
    // 初始化一个长度为10的链表
    for (int i = 0; i < 10; i++) {
        addNode(i);
    }

    // 删除值为2的节点
    deleteNode(2);

    // 输出链表中的元素
    printList();

    return 0;
}
```

这个程序演示了如何实现链表的基本操作，包括添加节点、输出链表中的元素和删除节点。
